from dataclasses import dataclass
from typing import Optional

DOMESTIC_RATES = [
    (1, 5.99),
    (5, 9.99),
    (10, 14.99),
    (25, 19.99),
    (float('inf'), 29.99),
]

INTERNATIONAL_RATES = [
    (1, 15.99),
    (5, 24.99),
    (10, 39.99),
    (25, 59.99),
    (float('inf'), 89.99),
]

DESTINATION_CONFIG = {
    'domestic': {
        'rates': DOMESTIC_RATES,
        'express_multiplier': 2.0,
        'fragile_surcharge': 4.99,
        'tax_rate': 0.08,
    },
    'international': {
        'rates': INTERNATIONAL_RATES,
        'express_multiplier': 2.5,
        'fragile_surcharge': 9.99,
        'tax_rate': 0.0,
    },
}


def _get_base_cost(weight: float, rates: list) -> float:
    for max_weight, cost in rates:
        if weight <= max_weight:
            return cost
    return rates[-1][1]


def calculate_shipping(weight: float, destination: str, is_express: bool, is_fragile: bool) -> float:
    config = DESTINATION_CONFIG.get(destination)
    if config is None:
        return -1

    base_cost = _get_base_cost(weight, config['rates'])

    if is_express:
        base_cost *= config['express_multiplier']

    if is_fragile:
        base_cost += config['fragile_surcharge']

    tax = base_cost * config['tax_rate']
    return base_cost + tax
